// NewQuery returns the generic Query interface for the given typed query.
func NewQuery(q ent.Query) (Query, error) {
	switch q := q.(type) {
	case *ent.AgentLogQuery:
		return &query[*ent.AgentLogQuery, predicate.AgentLog, agentlog.OrderOption]{typ: ent.TypeAgentLog, tq: q}, nil
	case *ent.AuditLogQuery:
		return &query[*ent.AuditLogQuery, predicate.AuditLog, auditlog.OrderOption]{typ: ent.TypeAuditLog, tq: q}, nil
	case *ent.GlobalSettingQuery:
		return &query[*ent.GlobalSettingQuery, predicate.GlobalSetting, globalsetting.OrderOption]{typ: ent.TypeGlobalSetting, tq: q}, nil
	case *ent.GroupQuery:
		return &query[*ent.GroupQuery, predicate.Group, group.OrderOption]{typ: ent.TypeGroup, tq: q}, nil
	case *ent.GroupMemberQuery:
		return &query[*ent.GroupMemberQuery, predicate.GroupMember, groupmember.OrderOption]{typ: ent.TypeGroupMember, tq: q}, nil
	case *ent.HostQuery:
		return &query[*ent.HostQuery, predicate.Host, host.OrderOption]{typ: ent.TypeHost, tq: q}, nil
	case *ent.HostMACQuery:
		return &query[*ent.HostMACQuery, predicate.HostMAC, hostmac.OrderOption]{typ: ent.TypeHostMAC, tq: q}, nil
	case *ent.ImageQuery:
		return &query[*ent.ImageQuery, predicate.Image, image.OrderOption]{typ: ent.TypeImage, tq: q}, nil
	case *ent.ImageTypeQuery:
		return &query[*ent.ImageTypeQuery, predicate.ImageType, imagetype.OrderOption]{typ: ent.TypeImageType, tq: q}, nil
	case *ent.ImagingLogQuery:
		return &query[*ent.ImagingLogQuery, predicate.ImagingLog, imaginglog.OrderOption]{typ: ent.TypeImagingLog, tq: q}, nil
	case *ent.InventoryQuery:
		return &query[*ent.InventoryQuery, predicate.Inventory, inventory.OrderOption]{typ: ent.TypeInventory, tq: q}, nil
	case *ent.ModuleQuery:
		return &query[*ent.ModuleQuery, predicate.Module, module.OrderOption]{typ: ent.TypeModule, tq: q}, nil
	case *ent.ModuleStatusQuery:
		return &query[*ent.ModuleStatusQuery, predicate.ModuleStatus, modulestatus.OrderOption]{typ: ent.TypeModuleStatus, tq: q}, nil
	case *ent.MulticastSessionQuery:
		return &query[*ent.MulticastSessionQuery, predicate.MulticastSession, multicastsession.OrderOption]{typ: ent.TypeMulticastSession, tq: q}, nil
	case *ent.OSTypeQuery:
		return &query[*ent.OSTypeQuery, predicate.OSType, ostype.OrderOption]{typ: ent.TypeOSType, tq: q}, nil
	case *ent.PendingMACQuery:
		return &query[*ent.PendingMACQuery, predicate.PendingMAC, pendingmac.OrderOption]{typ: ent.TypePendingMAC, tq: q}, nil
	case *ent.PrinterQuery:
		return &query[*ent.PrinterQuery, predicate.Printer, printer.OrderOption]{typ: ent.TypePrinter, tq: q}, nil
	case *ent.PrinterAssocQuery:
		return &query[*ent.PrinterAssocQuery, predicate.PrinterAssoc, printerassoc.OrderOption]{typ: ent.TypePrinterAssoc, tq: q}, nil
	case *ent.RefreshTokenQuery:
		return &query[*ent.RefreshTokenQuery, predicate.RefreshToken, refreshtoken.OrderOption]{typ: ent.TypeRefreshToken, tq: q}, nil
	case *ent.ScheduledTaskQuery:
		return &query[*ent.ScheduledTaskQuery, predicate.ScheduledTask, scheduledtask.OrderOption]{typ: ent.TypeScheduledTask, tq: q}, nil
	case *ent.SnapinQuery:
		return &query[*ent.SnapinQuery, predicate.Snapin, snapin.OrderOption]{typ: ent.TypeSnapin, tq: q}, nil
	case *ent.SnapinAssocQuery:
		return &query[*ent.SnapinAssocQuery, predicate.SnapinAssoc, snapinassoc.OrderOption]{typ: ent.TypeSnapinAssoc, tq: q}, nil
	case *ent.SnapinJobQuery:
		return &query[*ent.SnapinJobQuery, predicate.SnapinJob, snapinjob.OrderOption]{typ: ent.TypeSnapinJob, tq: q}, nil
	case *ent.SnapinTaskQuery:
		return &query[*ent.SnapinTaskQuery, predicate.SnapinTask, snapintask.OrderOption]{typ: ent.TypeSnapinTask, tq: q}, nil
	case *ent.StorageGroupQuery:
		return &query[*ent.StorageGroupQuery, predicate.StorageGroup, storagegroup.OrderOption]{typ: ent.TypeStorageGroup, tq: q}, nil
	case *ent.StorageNodeQuery:
		return &query[*ent.StorageNodeQuery, predicate.StorageNode, storagenode.OrderOption]{typ: ent.TypeStorageNode, tq: q}, nil
	case *ent.TaskQuery:
		return &query[*ent.TaskQuery, predicate.Task, task.OrderOption]{typ: ent.TypeTask, tq: q}, nil
	case *ent.UserQuery:
		return &query[*ent.UserQuery, predicate.User, user.OrderOption]{typ: ent.TypeUser, tq: q}, nil
	default:
		return nil, fmt.Errorf("unknown query type %T", q)
	}
}

type query[T any, P ~func(*sql.Selector), R ~func(*sql.Selector)] struct {
	typ string
	tq  interface {
		Limit(int) T
		Offset(int) T
		Unique(bool) T
		Order(...R) T
		Where(...P) T
	}
}

func (q query[T, P, R]) Type() string {
	return q.typ
}

func (q query[T, P, R]) Limit(limit int) {
	q.tq.Limit(limit)
}

func (q query[T, P, R]) Offset(offset int) {
	q.tq.Offset(offset)
}

func (q query[T, P, R]) Unique(unique bool) {
	q.tq.Unique(unique)
}

func (q query[T, P, R]) Order(orders ...func(*sql.Selector)) {
	rs := make([]R, len(orders))
	for i := range orders {
		rs[i] = orders[i]
	}
	q.tq.Order(rs...)
}

func (q query[T, P, R]) WhereP(ps ...func(*sql.Selector)) {
	p := make([]P, len(ps))
	for i := range ps {
		p[i] = ps[i]
	}
	q.tq.Where(p...)
}
